SELECT ?date WHERE {
  ?game wdt:P31 wd:Q18973810;
        wdt:P119 wd:Q839714;
        wdt:P205 wd:Q200493;
        wdt:P206 wd:Q7103;
        wdt:P585 ?date.
  wd:Q7103 wdt:P571 ?founded.
  FILTER (math:year(?founded) = 1962)
}
